// Aggregate all data from the three API calls
// Handle cases where APIs might return different structures

const items = $input.all();
const reportDate = new Date(Date.now() - 86400000).toISOString().split('T')[0];

// Default structure if APIs are not configured
const analytics = items[0]?.json || {
  pageviews: 0, sessions: 0, users: 0, bounce_rate: 0,
  top_pages: [], avg_session_duration: 0
};

const sales = items[1]?.json || {
  total_revenue: 0, orders: 0, avg_order_value: 0,
  new_customers: 0, returning_customers: 0
};

const social = items[2]?.json || {
  followers_gained: 0, total_engagement: 0,
  impressions: 0, top_post: null
};

const dataPrompt = `
## Analytics (${reportDate})
- Pageviews: ${analytics.pageviews || 'N/A'}
- Sessions: ${analytics.sessions || 'N/A'}
- Unique Users: ${analytics.users || 'N/A'}
- Bounce Rate: ${analytics.bounce_rate || 'N/A'}%
- Avg Session Duration: ${analytics.avg_session_duration || 'N/A'}s

## Sales (${reportDate})
- Total Revenue: $${sales.total_revenue || 0}
- Orders: ${sales.orders || 0}
- Avg Order Value: $${sales.avg_order_value || 0}
- New Customers: ${sales.new_customers || 0}
- Returning Customers: ${sales.returning_customers || 0}

## Social Media (${reportDate})
- New Followers: ${social.followers_gained || 0}
- Total Engagement: ${social.total_engagement || 0}
- Impressions: ${social.impressions || 0}
- Top Post: ${social.top_post || 'N/A'}
`;

return [{
  json: {
    report_date: reportDate,
    analytics,
    sales,
    social,
    data_prompt: dataPrompt
  }
}];

