const aiResponse = $input.first().json;
const prevData = $('Aggregate Report Data').first().json;

const reportContent = aiResponse.message?.content || aiResponse.choices?.[0]?.message?.content || 'Report generation failed.';
const reportDate = prevData.report_date;

// Build HTML email version
const htmlReport = `
<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; max-width: 680px; margin: 0 auto; padding: 24px;">
  <div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); padding: 24px; border-radius: 12px 12px 0 0; color: white;">
    <h1 style="margin: 0; font-size: 22px;">Daily Business Report</h1>
    <p style="margin: 8px 0 0; opacity: 0.9;">${reportDate}</p>
  </div>
  <div style="background: #fff; padding: 24px; border: 1px solid #e2e8f0; border-top: none; border-radius: 0 0 12px 12px;">
    ${reportContent.replace(/\n/g, '<br>').replace(/#{1,3}\s(.+)/g, '<h3 style="color: #4a5568; border-bottom: 2px solid #667eea; padding-bottom: 8px;">$1</h3>').replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')}
  </div>
  <p style="text-align: center; color: #a0aec0; font-size: 12px; margin-top: 16px;">Automated by n8n Daily Report Generator</p>
</div>`;

// Build Slack message
const slackMessage = `:bar_chart: *Daily Business Report - ${reportDate}*\n\n${reportContent.substring(0, 3000)}`;

return [{
  json: {
    report_date: reportDate,
    report_markdown: reportContent,
    report_html: htmlReport,
    slack_message: slackMessage,
    email_subject: `Daily Report: ${reportDate}`,
    analytics: prevData.analytics,
    sales: prevData.sales,
    social: prevData.social
  }
}];
